rss.channel:
    {{ config.title }}
    {{ config.base_url }}
    {{ config.description }}
    
    {{ now() | date(format="%a, %d %b %Y %H:%M:%S %z") }}
    {% for page in pages %}


      {{ page.title }}
      {{ page.permalink }}
      {{ page.summary | safe }}
      {{ page.date | date(format="%a, %d %b %Y %H:%M:%S %z") }}
      {{ page.permalink }}
    
    {% endfor %}
